#!/usr/bin/env perl

use strict;
use warnings;

my $redirect_url = "";

if (exists($ENV{"QUERY_STRING"}) && defined($ENV{"QUERY_STRING"})) {
    my @query_params = split("&", $ENV{"QUERY_STRING"});
    foreach my $param (@query_params) {
        if ($param =~ /^next=/) {
            $redirect_url = uri_unescape($param);
            last;
        }
    }
}

if (!$redirect_url || !is_valid_url($redirect_url)) {
    print "Location: /login\n\n";
} else {
    print "Location: $redirect_url\n\n";
}